parameters.text:
=Extract and clean the content brief from this Tally submission:

{{ JSON.stringify($json) }}

Return a JSON object with: topic (string), target_audience (string), tone (string), keywords (array of strings), cta (string), competitor_urls (array of strings), submission_id (string).

options.systemMessage:
You are a data extraction agent. Parse Tally form JSON into structured content brief fields.

CRITICAL: Return ONLY a raw JSON object. No markdown fences, no explanation.

OUTPUT SCHEMA: {"topic": "string", "target_audience": "string", "tone": "string", "keywords": ["string"], "cta": "string", "competitor_urls": ["string"], "submission_id": "string"}

parameters.jsCode:
const raw = $input.first().json.output || $input.first().json.text || '';
const clean = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
let parsed;
try {
  parsed = JSON.parse(clean);
} catch (e) {
  parsed = { topic: '', target_audience: '', tone: 'professional', keywords: [], cta: '', competitor_urls: [], submission_id: '', parse_error: e.message };
}
return [{ json: { ...parsed, processed_at: new Date().toISOString() } }];

parameters.text:
=Create a detailed blog post outline for the following brief:

Topic: {{ $json.topic }}
Target audience: {{ $json.target_audience }}
Tone: {{ $json.tone }}
Keywords to include: {{ ($json.keywords || []).join(', ') }}
Desired CTA: {{ $json.cta }}
Competitor URLs to reference: {{ ($json.competitor_urls || []).join(', ') }}

If competitor URLs are provided, factor their content angles into the outline so the post covers what they cover plus additional value.

Return a JSON object with: title (suggested post title), sections (array of objects each with heading and bullet_points array), estimated_word_count (number).

options.systemMessage:
You are a content strategist who builds well-structured blog outlines. Each section should have 3-5 bullet points that the writer will expand.

CRITICAL: Return ONLY a raw JSON object. No markdown fences, no explanation.

OUTPUT SCHEMA: {"title": "string", "sections": [{"heading": "string", "bullet_points": ["string"]}], "estimated_word_count": 1200}

parameters.jsCode:
const brief = $('Parse Brief Fields').first().json;
const raw = $input.first().json.output || $input.first().json.text || '';
const clean = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
let outline;
try {
  outline = JSON.parse(clean);
} catch (e) {
  outline = { title: brief.topic, sections: [], estimated_word_count: 0, parse_error: e.message };
}
return [{ json: { ...brief, outline_title: outline.title, outline_sections: outline.sections, estimated_word_count: outline.estimated_word_count } }];

parameters.text:
=Write a complete blog post draft based on this outline and brief:

Title: {{ $json.outline_title }}
Tone: {{ $json.tone }}
Target audience: {{ $json.target_audience }}
Keywords: {{ ($json.keywords || []).join(', ') }}
CTA: {{ $json.cta }}
Competitor URLs referenced: {{ ($json.competitor_urls || []).join(', ') }}
Outline sections: {{ JSON.stringify($json.outline_sections || []) }}

If competitor URLs were provided, ensure the draft adds unique value beyond what competitors cover.

Return a JSON object with: title (string), body (full blog post in markdown, including all sections expanded from the outline, ending with the CTA).

parameters.jsCode:
for (const item of $input.all()) {
  if (item.json.output) {
    try {
      // 1. Parse the AI JSON output
      const data = JSON.parse(item.json.output);

      // 2. Strip HTML tags and convert to plain text
      const stripHtml = (html) => {
        if (!html) return "";
        return html
          .replace(/<br\s*\/?>/gi, "\n") // Convert line breaks to newlines
          .replace(/<\/p>/gi, "\n\n")    // Double newline after paragraphs
          .replace(/<\/li>/gi, "\n")     // Newline after list items
          .replace(/<[^>]+>/g, "");      // Remove all remaining HTML tags
      };

      // 3. Extract clean title and body
      item.json.clean_title = data.title ? data.title.trim() : "";
      item.json.clean_body = data.body ? stripHtml(data.body).trim() : "";

      // Remove raw output to avoid downstream confusion
      delete item.json.output;

    } catch (e) {
      item.json.error = "Parsing error: " + e.message;
    }
  }
}

return $input.all();
